PROCEDURE isPrime(n)
{
   IF (n < 2)
   {
      RETURN (false)
   }
   i ← 2
   REPEAT UNTIL (i * i > n)
   {
      IF (n MOD i = 0)
      {
         RETURN (false)
      }
      i ← i + 1
   }
   RETURN (true)
}
