PROCEDURE applyToAll(lst, proc)
{
   result ← []
   FOR EACH item IN lst
   {
      APPEND(result, proc(item))
   }
   RETURN (result)
}
PROCEDURE triple(n)
{
   RETURN (n * 3)
}
DISPLAY(applyToAll([2, 4, 6], triple)[2])

PROCEDURE factorial(n)
{
   IF (n <= 1)
   {
      RETURN (1)
   }
   ELSE
   {
      RETURN (n * factorial(n - 1))
   }
}
