PROCEDURE compress(lst)
{
   result ← []
   i ← 1
   REPEAT UNTIL (i > LENGTH(lst))
   {
      IF (lst[i] ≠ 0)
      {
         APPEND(result, lst[i])
      }
      i ← i + 1
   }
   RETURN (result)
}
out ← compress([3, 0, 7, 0, 0, 4, 1])
DISPLAY(LENGTH(out))

PROCEDURE maxList(lst)
{
   m ← lst[1]
   i ← 2
   REPEAT UNTIL (i > LENGTH(lst))
   {
      IF (lst[i] > m)
      {
         m ← lst[i]
      }
      i ← i + 1
   }
   RETURN (m)
}
DISPLAY(maxList([5, 3, 9, 1, 7]))

